body.script:
        // Firebase SDK'larını yükle (Modüler yapı)
        import { initializeApp } from 'https://www.gstatic.com/firebasejs/9.22.0/firebase-app.js';
        import { getFirestore, collection, getDocs, query, orderBy, limit } from 'https://www.gstatic.com/firebasejs/9.22.0/firebase-firestore.js';

        // Firebase Konfigürasyonu (app.js'deki ile aynı olmalı)
        const firebaseConfig = {
            apiKey: "YOUR_API_KEY",
            authDomain: "YOUR_PROJECT_ID.firebaseapp.com",
            projectId: "YOUR_PROJECT_ID",
            storageBucket: "YOUR_PROJECT_ID.appspot.com",
            messagingSenderId: "YOUR_MESSAGING_SENDER_ID",
            appId: "YOUR_APP_ID"
        };

        // Firebase'i başlat
        const app = initializeApp(firebaseConfig);
        const db = getFirestore(app);

        // RSS Oluşturma Fonksiyonu
        async function generateRSS() {
            try {
                const articlesRef = collection(db, 'articles');
                const q = query(articlesRef, orderBy('createdAt', 'desc'), limit(20));
                const snapshot = await getDocs(q);

                let xml = '\n';
                xml += '\n';
                xml += '\n';
                xml += '  BİFTEK - Bilim ve Teknoloji Haberleri\n';
                xml += '  https://biftek-haberleri.com\n';
                xml += '  Bilim, Fen ve Teknoloji Kulübü\'nün resmi haber platformu.\n';
                xml += '  tr-tr\n';
                xml += '  ' + new Date().toUTCString() + '\n';
                xml += '  \n';

                snapshot.forEach((doc) => {
                    const article = doc.data();
                    const pubDate = article.createdAt ? article.createdAt.toDate().toUTCString() : new Date().toUTCString();
                    const description = article.summary || article.content.substring(0, 200) + '...';
                    const link = `https://biftek-haberleri.com/article.html?id=${doc.id}`;

                    xml += '  
\n';
                    xml += `    ${article.title}\n`;
                    xml += `    ${link}\n`;
                    xml += `    ${link}\n`;
                    xml += `    ${description}\n`;
                    xml += `    ${pubDate}\n`;
                    xml += `    ${article.category || 'Genel'}\n`;
                    if (article.authorName) {
                        xml += `    ${article.authorName}\n`;
                    }
                    xml += '  \n';
                });

                xml += '\n';
                xml += '';

                // XML içeriğini sayfaya yazdır ve MIME tipini ayarla
                document.open();
                document.write(xml);
                document.close();

            } catch (error) {
                console.error("RSS oluşturulurken hata:", error);
                // Hata durumunda boş bir RSS döndür
                document.open();
                document.write('HataRSS oluşturulamadı.');
                document.close();
            }
        }

        // Sayfa yüklendiğinde çalıştır
        window.addEventListener('load', generateRSS);
